import React, { useState, useEffect } from 'react';
import { fetchFigmaComponents } from '../figmaapi.js';

const FigmaButton = () => {
    const [buttonData, setButtonData] = useState(null);

    useEffect(() => {
        const fetchData = async () => {
            try {
                const data = await fetchFigmaComponents();
                setButtonData(data); // Store the fetched data in component state
            } catch (error) {
                console.error('Error fetching data:', error);
            }
        };

        fetchData();
    }, []); // Empty dependency array means it runs once, on component mount

    return (
        <div>
            {buttonData ? (
                <p>Button Data: {JSON.stringify(buttonData)}</p>
            ) : (
                <p>Loading button data...</p>
            )}
        </div>
    );
};

export default FigmaButton;
